def solve():
    import sys
    input = sys.stdin.read
    data = input().strip().splitlines()

    if not data:
        print("No limitation")
        return

    # Process the input data
    limitations = []
    for line in data:
        if line.strip():
            limitations.append(line.strip())

    if not limitations:
        print("No limitation")
    else:
        print(" - ".join(limitations))
